#!/usr/bin/env node
// E2E tests -- auto-generated by Clear compiler
// Run: node test.js
// Requires: server running on localhost:3000

const BASE = process.env.TEST_URL || "http://localhost:3000";
let passed = 0, failed = 0;
let _emailCounter = 0;
let _uniqueCounter = 0;
let _response, _responseBody;
let _lastCall = { method: "", path: "", line: 0 };
function _uniqueEmail() { return "test" + (++_emailCounter) + "@example.com"; }
function _uniqueText(base) { return base + "_" + (++_uniqueCounter); }

// Note: for clean re-runs, delete clear-data.db before starting the server
// unique constraints may cause 500s if stale data exists from a previous run

async function test(name, fn) {
  try {
    await fn();
    passed++;
    console.log("PASS:", name);
  } catch (err) {
    failed++;
    console.log("FAIL:", name, "-", err.message);
  }
}

function assert(condition, msg) { if (!condition) throw new Error(msg); }

async function run() {
  await test("Viewing all todos returns data", async () => {
    const r = await fetch(BASE + "/api/todos");
    assert(r.status === 200, "Expected 200, got " + r.status);
  });

  await test("Looking up a todo by ID works", async () => {
    const r = await fetch(BASE + "/api/todos/1");
    assert(r.status === 200 || r.status === 404, "Expected 200 or 404, got " + r.status);
  });

  await test("Creating a new todo succeeds", async () => {
    const payload = {};
    const r = await fetch(BASE + "/api/todos", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.id, "Response should have an id");
  });

  await test("Creating a todo without any data is rejected", async () => {
    const r = await fetch(BASE + "/api/todos", { method: "POST" });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("Todos appear in the list after being created", async () => {
    const r = await fetch(BASE + "/api/todos");
    const data = await r.json();
    assert(Array.isArray(data), "Expected array");
    assert(data.length > 0, "Expected at least one record (from earlier POST test)");
  });

  // --- Happy-path flow: create and view todo (API-only) ---
  await test("Endpoint: POSTing to /api/todos then GETting /api/todos returns the new todo (no UI button wired — see compiler warning)", async () => {
    const payload = {};
    // Create
    const createResp = await fetch(BASE + "/api/todos", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    assert(createResp.status === 201, "Create failed: " + createResp.status);
    const created = await createResp.json();
    // View all and check it's there
    const listResp = await fetch(BASE + "/api/todos");
    const list = await listResp.json();
    assert(Array.isArray(list), "Expected array of todos");
    assert(list.some(item => item.id === created.id), "Created todo should appear in the list");
  });

  console.log("");
  console.log("Results:", passed, "passed,", failed, "failed");
  process.exit(failed > 0 ? 1 : 0);
}

run();